#include "vimax/core/core.hpp"
#include <sstream>
#include <stdexcept>
namespace vimax {Core::Core(std::shared_ptr<IIntentResolver>r,std::shared_ptr<IPolicyEngine>p,std::shared_ptr<IAuditLog>a):resolver_(std::move(r)),policy_(std::move(p)),audit_(std::move(a)){if(!resolver_||!policy_||!audit_)throw std::invalid_argument("dependencies must not be null");}void Core::register_module(std::shared_ptr<IModule>m){registry_.register_module(std::move(m));}CoreResponse Core::handle(const UserMessage&m,bool user,bool local){CoreResponse o;auto i=resolver_->resolve(m);o.intent=i;if(i.name=="unknown"){o.message="Я пока не понял задачу. Скажите, что вы хотите сделать.";return o;}auto mod=registry_.find_for_intent(i.name);if(!mod){o.message="Намерение распознано, но модуль пока не установлен: "+i.name;return o;}auto p=mod->build_plan(i);for(auto&a:p.actions)a=policy_->evaluate(std::move(a));o.plan=p;if(!p.missing_fields.empty()){std::ostringstream s;s<<"Нужно уточнить:";for(const auto&f:p.missing_fields)s<<" "<<f;o.message=s.str();audit_->record(m,i,p,o.results);return o;}for(const auto&a:p.actions){if(!policy_->may_execute(a,local,user)){o.message="План готов и ожидает подтверждения пользователя.";audit_->record(m,i,p,o.results);return o;}o.results.push_back(mod->execute(a));}o.message=o.results.empty()?"План выполнен.":o.results.front().message;audit_->record(m,i,p,o.results);return o;}}
